import java.io.File;
import java.util.Scanner;

public class SecurePathTraversal {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter file name: ");
        String fileName = scanner.next();

        // Sanitize the input by removing any potentially harmful characters
        fileName = fileName.replaceAll("[^a-zA-Z0-9.-]", "");

        // Ensure that the file path is within a specific directory
        String basePath = "C:/users/documents/";
        File file = new File(basePath + fileName);

        try {
            if (file.getCanonicalPath().startsWith(basePath) && file.exists()) {
                System.out.println("File exists.");
            } else {
                System.out.println("File not found.");
            }
        } catch (Exception e) {
            System.out.println("Error accessing file.");
            e.printStackTrace();
        }
    }
